mapper.select:
SELECT log_id, session_id, employee_id, action, request_content, response_content, masked_response_content, response_time_ms, timestamp
FROM t_audit_log


        AND timestamp >= #{query.startTime}


        AND timestamp <= #{query.endTime}


        AND employee_id = #{query.employeeId}


        AND action = #{query.intent}


        AND session_id = #{query.sessionId}


ORDER BY timestamp DESC
